  1→import {
  2→  createContext,
  3→  useContext,
  4→  useEffect,
  5→  useMemo,
  6→  useReducer,
  7→} from "react";
  8→import Cookies from "js-cookie";
  9→import { useNavigate } from "react-router-dom";
 10→import { getUserStagingKey, isStaging } from "../../utils/environmentVariables";
 11→import {
 12→  SentryBreadcrumbTypes,
 13→  leaveBreadcrumb,
 14→} from "../../utils/errorReporting";
 15→import { fetchWithRetry, getUserStagingHeader } from "../../utils/request";
 16→
 17→type AuthProviderDispatchMethods = {
 18→  /**
 19→   * localLogin - used only if `shouldUseLocalAuth` is true.
 20→   * @param credentials - credentials to login with
 21→   * @param credentials.username - username
 22→   * @param credentials.password - password
 23→   */
 24→  localLogin: (credentials: { username: string; password: string }) => void;
 25→  /**
 26→   * logoutAndRedirect - calls the logout endpoint for localAuth
 27→   * or redirects to the remoteAuthURL for remoteAuth.
 28→   */
 29→  logoutAndRedirect: () => void;
 30→  /**
 31→   * A helper to mark the user as authenticated in local state
 32→   * (useful if you get a successful check from somewhere else).
 33→   */
 34→  dispatchAuthenticated: () => void;
 35→};
 36→
 37→type AuthState = {
 38→  /**
 39→   * `isAuthenticated` is a boolean that determines whether the user is currently authenticated.
 40→   */
 41→  isAuthenticated: boolean;
 42→  /**
 43→   * `hasCheckedAuth` is a boolean that determines whether the user's authentication status has been checked.
 44→   * This is useful for determining whether to show a loading spinner or not.
 45→   */
 46→  hasCheckedAuth: boolean;
 47→};
 48→
 49→const AuthStateContext = createContext<
 50→  (AuthState & AuthProviderDispatchMethods) | null
 51→>(null);
 52→
 53→type AuthAction = { type: "SET_AUTH"; payload: boolean };
 54→
 55→const authReducer = (state: AuthState, action: AuthAction): AuthState => {
 56→  switch (action.type) {
 57→    case "SET_AUTH":
 58→      return { isAuthenticated: action.payload, hasCheckedAuth: true };
 59→    default:
 60→      return state;
 61→  }
 62→};
 63→
 64→/**
 65→ * `AuthProvider` is a context provider that manages the authentication state of the application.
 66→ * It provides support for both local and remote authentication strategies.
 67→ * localAuthentication is used for local development when connected to a local development environment and remoteAuthentication is used for production or when connected to a remote development environment.
 68→ * @param props -
 69→ * @param props.children - The children of the AuthProvider component.
 70→ * @param props.localAuthRoute - The route of the local authentication provider UI. (Only used in local development)
 71→ * @param props.remoteAuthURL - The URL that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is false.
 72→ * @param props.shouldUseLocalAuth - A boolean that determines which authentication strategy we should use.
 73→ * @param props.evergreenAppURL - The URL of the evergreen instance we will authenticate against.
 74→ * @returns - The AuthProvider component.
 75→ */
 76→const AuthProvider: React.FC<{
 77→  children: React.ReactNode;
 78→  /** `evergreenAppURL` is the URL of the evergreen instance we will authenticate against */
 79→  evergreenAppURL: string;
 80→  /** `remoteAuthURL` is the URL that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is false */
 81→  remoteAuthURL: string;
 82→  /** `localAuthRoute` is the route that we should redirect the user to if they are not currently authenticated when `shouldUseLocalAuth` is true */
 83→  localAuthRoute: string;
 84→  /** `shouldUseLocalAuth` determines which authentication strategy we should use. */
 85→  shouldUseLocalAuth: boolean;
 86→}> = ({
 87→  children,
 88→  evergreenAppURL,
 89→  localAuthRoute,
 90→  remoteAuthURL,
 91→  shouldUseLocalAuth,
 92→}) => {
 93→  const [state, dispatch] = useReducer(authReducer, {
 94→    isAuthenticated: false,
 95→    hasCheckedAuth: false,
 96→  });
 97→
 98→  const navigate = useNavigate();
 99→
100→  const authMethods: AuthProviderDispatchMethods = useMemo(
101→    () => ({
102→      /**
103→       * localLogin - used only if `shouldUseLocalAuth` is true.
104→       * @param credentials - credentials to login with
105→       * @param credentials.username - username
106→       * @param credentials.password - password
107→       */
108→      localLogin: async ({
109→        password,
110→        username,
111→      }: {
112→        username: string;
113→        password: string;
114→      }) => {
115→        await fetch(`${evergreenAppURL}/login`, {
116→          body: JSON.stringify({ password, username }),
117→          credentials: "include",
118→          method: "POST",
119→        }).then((response) => {
120→          // Dispatch once so that hasCheckedAuth is set to true along with isAuthenticated.
121→          dispatch({ type: "SET_AUTH", payload: response.ok });
122→          if (!response.ok) {
123→            // I know we don't like using alerts but this is a dev only feature
124→            alert("Error logging in, username or password invalid");
125→          }
126→        });
127→      },
128→      /**
129→       * logoutAndRedirect - calls the logout endpoint for localAuth
130→       * or redirects to the remoteAuthURL for remoteAuth.
131→       */
132→      logoutAndRedirect: async () => {
133→        // Set the staging cookie whether or not the state is currently authenticated so personal stagings can be routed correctly.
134→        const stagingKey = getUserStagingKey();
135→        if (isStaging() && stagingKey) {
136→          Cookies.set("evg-staging-environment", stagingKey, {
137→            expires: 365,
138→          });
139→        }
140→        if (state.isAuthenticated) {
141→          try {
142→            await fetch(`${evergreenAppURL}/logout`, {
143→              credentials: "include",
144→              method: "GET",
145→              redirect: "manual",
146→              headers: getUserStagingHeader(),
147→            });
148→          } catch (error) {
149→            leaveBreadcrumb(
150→              "logoutAndRedirect",
151→              { error },
152→              SentryBreadcrumbTypes.Error,
153→            );
154→          }
155→        }
156→        // Reset auth state.
157→        if (shouldUseLocalAuth) {
158→          dispatch({ type: "SET_AUTH", payload: false });
159→          navigate(localAuthRoute);
160→        } else {
161→          const encodedOrigin = encodeURIComponent(window.location.href);
162→          const redirectURL = `${remoteAuthURL}?redirect=${encodedOrigin}`;
163→          window.location.href = redirectURL;
164→        }
165→      },
166→      /**
167→       * A helper to mark the user as authenticated in local state.
168→       */
169→      dispatchAuthenticated: () => {
170→        leaveBreadcrumb("User authenticated", {}, SentryBreadcrumbTypes.User);
171→        dispatch({ type: "SET_AUTH", payload: true });
172→      },
173→    }),
174→    [
175→      state.isAuthenticated,
176→      evergreenAppURL,
177→      localAuthRoute,
178→      remoteAuthURL,
179→      shouldUseLocalAuth,
180→      navigate,
181→    ],
182→  );
183→
184→  useEffect(() => {
185→    // Testing if the user is authenticated
186→    fetchWithRetry(`${evergreenAppURL}/graphql/query`, {
187→      credentials: "include",
188→      headers: {
189→        ...getUserStagingHeader(),
190→        "content-type": "application/json",
191→      },
192→      body: JSON.stringify({
193→        query: "{\n  user {\n    userId\n  }\n}",
194→        variables: {},
195→      }),
196→      method: "POST",
197→      mode: "cors",
198→    })
199→      .then(() => {
200→        dispatch({ type: "SET_AUTH", payload: true });
201→      })
202→      .catch(() => {
203→        dispatch({ type: "SET_AUTH", payload: false });
204→        authMethods.logoutAndRedirect();
205→      });
206→  }, [evergreenAppURL, authMethods]);
207→
208→  const authProviderValue = useMemo(
209→    () => ({
210→      isAuthenticated: state.isAuthenticated,
211→      hasCheckedAuth: state.hasCheckedAuth,
212→      ...authMethods,
213→    }),
214→    [state, authMethods],
215→  );
216→
217→  return (
218→    <AuthStateContext.Provider value={authProviderValue}>
219→      {children}
220→    </AuthStateContext.Provider>
221→  );
222→};
223→
224→const useAuthProviderContext = (): AuthState & AuthProviderDispatchMethods => {
225→  const authState = useContext(AuthStateContext);
226→  if (authState === null || authState === undefined) {
227→    throw new Error(
228→      "useAuthStateContext must be used within an auth context provider",
229→    );
230→  }
231→  return authState;
232→};
233→
234→export { AuthProvider, useAuthProviderContext };
235→

  1→import {
  2→  ReactNode,
  3→  createContext,
  4→  useCallback,
  5→  useContext,
  6→  useMemo,
  7→} from "react";
  8→import {
  9→  ToastProvider as LGToastProvider,
 10→  Variant,
 11→  useToast,
 12→} from "@leafygreen-ui/toast";
 13→import { WordBreak } from "../../components/styles";
 14→import {
 15→  TOAST_TIMEOUT,
 16→  mapLeafyGreenVariantToTitle,
 17→  mapLeafyGreenVariantToToast,
 18→} from "./constants";
 19→import { DispatchToast, DispatchToastWithProgress, ToastParams } from "./types";
 20→
 21→interface ToastContextState {
 22→  success: DispatchToast;
 23→  warning: DispatchToast;
 24→  error: DispatchToast;
 25→  info: DispatchToast;
 26→  progress: DispatchToastWithProgress;
 27→}
 28→
 29→export const ToastContext = createContext<ToastContextState | null>(null);
 30→
 31→const useToastContext = (): ToastContextState => {
 32→  const context = useContext(ToastContext);
 33→  if (context === null || context === undefined) {
 34→    throw new Error("useToastContext must be used within a ToastProvider");
 35→  }
 36→  return context;
 37→};
 38→
 39→const ToastProviderCore: React.FC<{ children: ReactNode }> = ({ children }) => {
 40→  const { pushToast } = useToast();
 41→  const dispatchToast = useCallback(
 42→    ({
 43→      closable,
 44→      message,
 45→      onClose,
 46→      progress,
 47→      shouldTimeout,
 48→      timeout,
 49→      title,
 50→      variant,
 51→    }: ToastParams) => {
 52→      let toastTimeout = null;
 53→      if (timeout !== undefined) {
 54→        toastTimeout = timeout;
 55→      } else if (shouldTimeout) {
 56→        toastTimeout = TOAST_TIMEOUT;
 57→      }
 58→
 59→      return pushToast({
 60→        // @ts-expect-error: data-cy doesn't exist as a prop on Toast but it will be propagated correctly.
 61→        "data-cy": "toast",
 62→        "data-variant": mapLeafyGreenVariantToToast[variant],
 63→        description: <WordBreak>{message}</WordBreak>,
 64→        dismissible: closable,
 65→        onClose: closable ? onClose : undefined,
 66→        progress,
 67→        timeout: toastTimeout,
 68→        title: title || mapLeafyGreenVariantToTitle[variant],
 69→        variant,
 70→      });
 71→    },
 72→    [pushToast],
 73→  );
 74→
 75→  const toastContext: ToastContextState = useMemo(() => {
 76→    const defaultOptions = {
 77→      onClose: () => {},
 78→      shouldTimeout: true,
 79→      title: "",
 80→    };
 81→
 82→    return {
 83→      error: (message = "", closable = true, options = {}) =>
 84→        dispatchToast({
 85→          closable,
 86→          message,
 87→          variant: Variant.Warning,
 88→          ...defaultOptions,
 89→          ...options,
 90→        }),
 91→      info: (message = "", closable = true, options = {}) =>
 92→        dispatchToast({
 93→          closable,
 94→          message,
 95→          variant: Variant.Note,
 96→          ...defaultOptions,
 97→          ...options,
 98→        }),
 99→      progress: (message = "", progress = 0.5, closable = true, options = {}) =>
100→        dispatchToast({
101→          closable,
102→          message,
103→          progress,
104→          variant: Variant.Progress,
105→          ...defaultOptions,
106→          ...options,
107→        }),
108→      success: (message = "", closable = true, options = {}) =>
109→        dispatchToast({
110→          closable,
111→          message,
112→          variant: Variant.Success,
113→          ...defaultOptions,
114→          ...options,
115→        }),
116→      warning: (message = "", closable = true, options = {}) =>
117→        dispatchToast({
118→          closable,
119→          message,
120→          variant: Variant.Important,
121→          ...defaultOptions,
122→          ...options,
123→        }),
124→    };
125→  }, [dispatchToast]);
126→
127→  return (
128→    <ToastContext.Provider value={toastContext}>
129→      {children}
130→    </ToastContext.Provider>
131→  );
132→};
133→
134→const ToastProvider: React.FC<{
135→  children?: ReactNode;
136→  portalClassName?: string;
137→}> = ({ children, portalClassName }) => (
138→  <LGToastProvider portalClassName={portalClassName}>
139→    <ToastProviderCore>{children}</ToastProviderCore>
140→  </LGToastProvider>
141→);
142→
143→export { ToastProvider, useToastContext };
144→

