 1→import "@testing-library/jest-dom/vitest";
 2→import "vitest-canvas-mock";
 3→import { vi } from "vitest";
 4→
 5→// @ts-expect-error: Workaround for a bug in @testing-library/react.
 6→// It prevents Vitest's fake timers from functioning with user-event.
 7→// https://github.com/testing-library/react-testing-library/issues/1197
 8→globalThis.jest = vi;
 9→
10→beforeEach(() => {
11→  // jsdom 28 recognizes the popover attribute (hiding elements by default)
12→  // but doesn't fully implement showPopover/hidePopover.
13→  HTMLElement.prototype.showPopover = vi.fn(function mock(this: HTMLElement) {
14→    this.style.display = "block";
