 1→import { useQuery } from "@apollo/client/react";
 2→import {
 3→  AdminBetaFeaturesQuery,
 4→  AdminBetaFeaturesQueryVariables,
 5→  BetaFeatures,
 6→  UserBetaFeaturesQuery,
 7→  UserBetaFeaturesQueryVariables,
 8→} from "../../gql/generated/types";
 9→import { ADMIN_BETA_FEATURES, USER_BETA_FEATURES } from "../../gql/queries";
10→
11→/**
12→ * `useAdminBetaFeatures` returns the beta features defined at the admin level.
13→ * @returns an object containing
14→ * - adminBetaSettings: admin beta features settings
15→ * - loading: boolean representing query loading state
16→ */
17→export const useAdminBetaFeatures = () => {
18→  const { data, loading } = useQuery<
19→    AdminBetaFeaturesQuery,
20→    AdminBetaFeaturesQueryVariables
21→  >(ADMIN_BETA_FEATURES);
22→  const { spruceConfig } = data ?? {};
23→  const { ui } = spruceConfig ?? {};
24→  const { betaFeatures } = ui ?? {};
25→  return { adminBetaSettings: betaFeatures, loading };
26→};
27→
28→/**
29→ * `useUserBetaFeatures` returns the user's beta feature settings.
30→ * @returns an object containing
31→ * - userBetaSettings: user's beta features settings
32→ * - loading: boolean representing query loading state
33→ */
34→export const useUserBetaFeatures = () => {
35→  const { data, loading } = useQuery<
36→    UserBetaFeaturesQuery,
37→    UserBetaFeaturesQueryVariables
38→  >(USER_BETA_FEATURES, {
39→    variables: {},
40→  });
41→  const { user } = data ?? {};
42→  const { betaFeatures } = user ?? {};
43→  return { userBetaSettings: betaFeatures, loading };
44→};
45→
46→/**
47→ * `useMergedBetaFeatures` returns the result of merging admin and user level beta features.
48→ * @returns an object containing
49→ * - betaFeatures: merged beta features
50→ * - loading: boolean representing query loading state
51→ */
52→export const useMergedBetaFeatures = () => {
53→  const { adminBetaSettings, loading: adminLoading } = useAdminBetaFeatures();
54→  const { loading: userLoading, userBetaSettings } = useUserBetaFeatures();
55→
56→  if (!adminBetaSettings || !userBetaSettings) {
57→    return { mergedBetaFeatures: undefined, loading: false };
58→  }
59→
60→  const mergedBetaFeatures: BetaFeatures = {};
61→
62→  return {
63→    betaFeatures: mergedBetaFeatures,
64→    loading: adminLoading || userLoading,
65→  };
66→};
67→

  1→import { useCallback, useEffect, useMemo, useRef } from "react";
  2→import { ParseOptions } from "query-string";
  3→import { useLocation, useNavigate } from "react-router-dom";
  4→import { conditionalToArray } from "../../utils/array";
  5→import { parseQueryString, stringifyQuery } from "../../utils/query-string";
  6→
  7→type QueryParams = { [key: string]: unknown };
  8→type QueryParamsUpdater = QueryParams | ((current: QueryParams) => QueryParams);
  9→type SetQueryParams = (params: QueryParamsUpdater) => void;
 10→
 11→/**
 12→ * `useQueryParams` returns all of the query params that exist in the url.
 13→ * @param parseOptions - options which define how to parse params from the url (optional)
 14→ * @returns a tuple containing the parsed query params and a function to set the query params.
 15→ * The setter supports both direct values and functional updates (like useState).
 16→ */
 17→const useQueryParams = (
 18→  parseOptions?: ParseOptions,
 19→): readonly [QueryParams, SetQueryParams] => {
 20→  const location = useLocation();
 21→  const navigate = useNavigate();
 22→
 23→  // The url colors=red%2Cblue,green becomes colors=red%2Cblue%2Cgreen
 24→  // after using URLSearchParams.toString(), so we lose the contex of `,`.
 25→  // So `parseQueryString` can't tell the difference and we end up breaking the filters
 26→  const rawSearch = location.search.replace(/^\?/, "");
 27→
 28→  const searchParamsObject = useMemo(
 29→    () => parseQueryString(rawSearch, parseOptions ?? {}),
 30→    [rawSearch, parseOptions],
 31→  );
 32→
 33→  // Use a ref to track current params so the setter can read fresh values
 34→  // without needing searchParams in its dependency array.
 35→  // This is necessary because react-router-dom's setSearchParams is not stable.
 36→  const paramsRef = useRef(searchParamsObject);
 37→  useEffect(() => {
 38→    paramsRef.current = searchParamsObject;
 39→  }, [searchParamsObject]);
 40→
 41→  const setQueryString = useCallback(
 42→    (updater: QueryParamsUpdater) => {
 43→      const currentParams = paramsRef.current;
 44→      const newParams =
 45→        typeof updater === "function" ? updater(currentParams) : updater;
 46→
 47→      const stringifiedQuery = stringifyQuery(newParams, {
 48→        skipEmptyString: false,
 49→      });
 50→      navigate(`?${stringifiedQuery}`, { replace: true });
 51→    },
 52→    [navigate],
 53→  );
 54→
 55→  return [searchParamsObject, setQueryString] as const;
 56→};
 57→
 58→/**
 59→ * `useQueryParam` allows you to interact with a query param in the same way you would use a useState hook.
 60→ * The first argument is the name of the query param. The second argument is the initial value of the query param.
 61→ * `useQueryParam` will default to the second argument if the query param is not present in the url.
 62→ * @param param - the name of the query param
 63→ * @param defaultParam - the default value of the query param
 64→ * @param parseOptions - options which define how to parse params from the url (optional)
 65→ * @returns a tuple containing the parsed query param and a function to set the query param.
 66→ * The setter has a stable identity and will not change between renders.
 67→ */
 68→const useQueryParam = <T>(
 69→  param: string,
 70→  defaultParam: T,
 71→  parseOptions?: ParseOptions,
 72→): readonly [T, (set: T) => void] => {
 73→  const [searchParams, setSearchParams] = useQueryParams(parseOptions);
 74→
 75→  // Capture the initial defaultParam to avoid recomputation when callers
 76→  // pass inline arrays/objects (e.g., useQueryParam("filters", []))
 77→  const defaultParamRef = useRef(defaultParam);
 78→
 79→  const setQueryParam = useCallback(
 80→    (value: T) => {
 81→      setSearchParams((current) => ({
 82→        ...current,
 83→        [param]: value,
 84→      }));
 85→    },
 86→    [setSearchParams, param],
 87→  );
 88→
 89→  // This lint error is a false positive: https://github.com/facebook/react/issues/34775
 90→  /* eslint-disable react-hooks/refs */
