 19→  onFilter?: () => void;
 20→  "data-cy"?: string;
 21→}
 22→export interface TreeDataChildEntry {
 23→  title: string;
 24→  value: string;
 25→  key: string;
 26→}
 27→export interface TreeDataEntry extends TreeDataChildEntry {
 28→  children?: TreeDataChildEntry[];
 29→}
 30→
 31→export const TreeSelect: React.FC<TreeSelectProps> = ({
 32→  "data-cy": dataCy,
 33→  isVisible = true,
 34→  onChange,
 35→  onFilter,
 36→  onReset,
 37→  setOptionsLabel = () => undefined,
 38→  state,
 39→  tData,
 40→}) => {
 41→  const allValues = getAllValues(tData);
 42→  // removes values not included in tData
 43→  const filteredState = state.filter((value) => allValues.includes(value));
 44→  const optionsLabel = filteredState.includes(ALL_VALUE)
 45→    ? ALL_COPY
 46→    : filteredState
 47→        .reduce(
 48→          // remove children nodes if parent exists in state
 49→          (accum, value) => {
 50→            const { target } = findNode({ value, tData });
 51→            if (target.children) {
 52→              return accum.filter(
 53→                // @ts-expect-error: FIXME. This comment was added by an automated script.
 54→                (v) => !target.children.find((child) => child.value === v),
 55→              );
 56→            }
 57→            return accum;
 58→          },
 59→          [...filteredState],
 60→        )
 61→        .map((value) => findNode({ value, tData }).target.title)
 62→        .join(", ");
 63→
 64→  useEffect(() => {
 65→    setOptionsLabel(optionsLabel);
 66→  }, [optionsLabel, setOptionsLabel]);
 67→
 68→  if (!isVisible) {
 69→    return null;
 70→  }
 71→
 72→  return (
 73→    <CheckboxContainer data-cy={dataCy || "tree-select-options"}>
 74→      {renderCheckboxes({
 75→        state: filteredState,
 76→        tData,
 77→        onChange,
 78→      })}
 79→      {onReset && onFilter && (
 80→        <FilterInputControls
 81→          onClickReset={onReset}
 82→          onClickSubmit={onFilter}
 83→          submitButtonCopy="Filter"
 84→        />
 85→      )}
 86→    </CheckboxContainer>
 87→  );
 88→};
 89→
 90→// depth first traversal checkbox data.
 91→// pushes parent then children to rows array
 92→// keeps track of level for indentation
 93→const renderCheckboxes = ({
 94→  onChange,
 95→  state,
 96→  tData,
 97→}: {
 98→  tData: TreeDataEntry[];
 99→  state: string[];
100→  onChange: (v: [string]) => void;
101→}): React.JSX.Element[] => {
102→  const rows: React.JSX.Element[] = [];
103→  tData.forEach((entry) => {
104→    // @ts-expect-error: FIXME. This comment was added by an automated script.
105→    renderCheckboxesHelper({ rows, data: entry, onChange, state, tData });
106→  });
107→  return rows;
108→};
109→
110→const renderCheckboxesHelper = ({
111→  data,
112→  onChange,
113→  rows,
114→  state,
115→  tData,
116→}: {
117→  rows: React.JSX.Element[];
118→  data: TreeDataEntry;
119→  onChange: (v: string[]) => void;
120→  state: string[];
121→  tData: TreeDataEntry[];
122→}): void => {
123→  // push parent
124→  const onChangeFn = (): void =>
125→    handleOnChange({ state, value: data.value, onChange, tData });
126→  rows.push(
127→    <CheckboxWrapper key={data.key} isAll={data.value === ALL_VALUE} level={0}>
128→      <Checkbox
129→        bold={false}
130→        checked={state.includes(data.value)}
131→        className="cy-checkbox"
132→        data-cy="checkbox"
133→        label={data.title}
134→        onChange={onChangeFn}
135→      />
136→    </CheckboxWrapper>,
137→  );
138→  // then examine children
139→  if (data.children) {
140→    data.children.forEach((child) => {
141→      const onChangeChildFn = (): void =>
142→        handleOnChange({ state, value: child.value, onChange, tData });
143→      rows.push(
144→        <CheckboxWrapper
145→          key={`${data.key}-${child.key}`}
146→          isAll={child.value === ALL_VALUE}
147→          level={1}
148→        >
149→          <Checkbox
150→            bold={false}
151→            checked={state.includes(child.value)}
152→            className="cy-checkbox"
153→            data-cy="checkbox"
154→            label={child.title}
155→            onChange={onChangeChildFn}
156→          />
157→        </CheckboxWrapper>,
158→      );
159→    });
160→  }
161→};
162→
163→// Executes when checkbox is clicked
164→const handleOnChange = ({
165→  onChange,
166→  state,
167→  tData, // callback function
168→  value,
169→}: {
170→  state: string[];
171→  value: string;
172→  onChange: (v: string[]) => void;
173→  tData: TreeDataEntry[];
174→}): void => {
175→  const isAlreadyChecked = state.includes(value); // is checkbox already selected
176→  const { parent, siblings, target } = findNode({ value, tData });
177→  const isParent = target.children;
178→  const isAll = target.value === ALL_VALUE; // is all button clicked
179→  if (!target) {
180→    onChange([...state]);
181→  }
182→  // is all button checked
183→  if (isAll) {
184→    if (isAlreadyChecked) {
185→      onChange([]);
186→    } else {
187→      onChange(getAllValues(tData));
188→    }
189→  } else if (isParent) {
190→    // has list of children
191→    // @ts-expect-error: FIXME. This comment was added by an automated script.
192→    const childrenValues = target.children.map((child) => child.value);
193→    if (isAlreadyChecked) {
194→      onChange(
195→        adjustAll({
196→          resultState: state.filter(
197→            (v) => v !== value && !childrenValues.includes(v),
198→          ),
199→          tData,
200→        }),
201→      );
202→    } else {
203→      const resultState = Array.from(
204→        new Set([...state, value, ...childrenValues]),
205→      );
206→      onChange(adjustAll({ resultState, tData }));
207→    }
208→  } else {
209→    // does not have list of children, could be child
210→    const parentValue = parent ? parent.value : "";
211→    if (isAlreadyChecked) {
212→      onChange(
213→        adjustAll({
214→          resultState: state.filter((v) => v !== value && v !== parentValue),
215→          tData,
216→        }),
217→      );
218→    } else {
219→      let siblingsChecked = true;
220→      siblings.forEach((sibling) => {
221→        siblingsChecked = siblingsChecked && state.includes(sibling.value);
222→      });
223→      const shouldCheckParent = parentValue && siblingsChecked;
224→      // use set in case parent.value already exists in state
225→      const resultState = Array.from(
226→        new Set(
227→          [...state, value].concat(shouldCheckParent ? [parentValue] : []),
228→        ),
229→      );
230→      onChange(adjustAll({ resultState, tData }));
231→    }
232→  }
233→};
234→
235→// selects or deselects the All checkbox depending on current options
236→const adjustAll = ({
237→  resultState,
238→  tData,
239→}: {
240→  resultState: string[];
241→  tData: TreeDataEntry[];
242→}): string[] => {
243→  const allValues = getAllValues(tData).filter((value) => value !== ALL_VALUE);
244→  const resultStateHasAllValues = allValues.reduce(
245→    (accum, value) => accum && resultState.includes(value),
246→    true,
247→  );
248→  // convert to set in case all exists in URL when its not supposed to
249→  const resultStateSet = new Set(resultState);
250→  if (resultStateHasAllValues) {
251→    resultStateSet.add(ALL_VALUE);
252→  } else {
253→    resultStateSet.delete(ALL_VALUE);
254→  }
255→  return Array.from(resultStateSet);
256→};
257→
258→interface FindNodeResult {
259→  target: TreeDataEntry;
260→  parent: TreeDataEntry;
261→  siblings: TreeDataEntry[] | TreeDataChildEntry[];
262→}
263→
264→const findNode = ({
265→  tData,
266→  value,
267→}: {
268→  value: string;
269→  tData: TreeDataEntry[];
270→}): FindNodeResult => {
271→  for (const curr of tData) {
272→    if (curr.value === value) {
273→      return {
274→        target: curr,
275→        // @ts-expect-error: FIXME. This comment was added by an automated script.
276→        parent: null,
277→        siblings: tData.filter((v) => v.value !== value),
278→      };
279→    }
280→    if (curr.children) {
281→      const child = curr.children.find((c) => c.value === value);
282→      if (child) {
283→        return {
284→          target: child,
285→          parent: curr,
286→          siblings: curr.children.filter((c) => c.value !== value),
287→        };
288→      }
289→    }
290→  }
291→  return {
292→    // @ts-expect-error: FIXME. This comment was added by an automated script.
293→    target: null,
294→    // @ts-expect-error: FIXME. This comment was added by an automated script.
295→    parent: null,
296→    siblings: [],
297→  };
298→};
299→
300→// returns all values in tData from parents and children
301→const getAllValues = (tData: TreeDataEntry[]): string[] =>
302→  tData.reduce((accum, currNode) => {
303→    const childrenValues = currNode.children
304→      ? currNode.children.map((child) => child.value)
305→      : [];
306→    // @ts-expect-error: FIXME. This comment was added by an automated script.
307→    return accum.concat([currNode.value]).concat(childrenValues);
308→  }, []);
309→
310→const CheckboxWrapper = styled.div<{ level: number; isAll: boolean }>`
311→  padding-left: ${({ level }) => `${level}em`};
312→  padding-top: ${size.xxs};
313→  padding-bottom: ${size.xxs};
314→  ${({ isAll }) => isAll && `border-bottom: 1px solid ${gray.light2};`}
315→`;
316→
317→const CheckboxContainer = styled.div`
318→  min-width: 150px; // need to set this as side effect of getPopupContainer
319→  font-weight: normal; // need to set this as side effect of getPopupContainer
320→`;
