 1→import React, {
 2→  useEffect,
 3→  useRef,
 4→  ForwardRefExoticComponent,
 5→  RefAttributes,
 6→} from "react";
 7→
 8→interface AnimatedIconProps {
 9→  icon: ForwardRefExoticComponent<
10→    RefAttributes<SVGSVGElement> & {
11→      onMouseEnter?: () => void;
12→      onMouseLeave?: () => void;
13→    }
14→  >;
15→  alwaysAnimate?: boolean;
16→}
17→
18→/**
19→ * `AnimatedIcon` is a component that wraps an SVG icon and adds mouse enter and mouse leave events to pause and unpause animations.
20→ * @param props - The props for the `AnimatedIcon` component.
21→ * @param props.icon - The SVG icon to animate.
22→ * @param props.alwaysAnimate - Whether the icon should always animate or not. Defaults to false.
23→ * @returns - A React component that wraps an SVG icon and adds mouse enter and mouse leave events to pause and unpause animations.
24→ */
25→const AnimatedIcon: React.FC<AnimatedIconProps> = ({
26→  alwaysAnimate = false,
27→  icon,
28→  ...rest
29→}) => {
30→  const iconRef = useRef<SVGSVGElement>(null);
31→  // Animations should be paused by default on page load.
32→  useEffect(() => {
33→    // Check if the SVG has animations before pausing them.
34→    // This is necessary because some SVGs may not have animations.
35→    //  and calling pauseAnimations on an SVG without animations will throw an error.
36→    if (iconRef.current && hasAnimations(iconRef.current) && !alwaysAnimate) {
37→      iconRef.current?.pauseAnimations();
38→    }
39→  }, [alwaysAnimate]);
40→
41→  const onMouseEnter = () => {
42→    if (hasAnimations(iconRef.current!) && !alwaysAnimate) {
43→      iconRef.current?.unpauseAnimations();
44→    }
45→  };
46→
47→  const onMouseLeave = () => {
48→    if (hasAnimations(iconRef.current!) && !alwaysAnimate) {
49→      iconRef.current?.pauseAnimations();
50→    }
51→  };
52→
53→  const Icon = icon;
54→  return (
55→    <Icon
56→      ref={iconRef}
57→      onMouseEnter={onMouseEnter}
58→      onMouseLeave={onMouseLeave}
59→      {...rest}
60→    />
61→  );
62→};
63→
64→/**
65→ * `hasAnimations` checks if an SVG element has animations. This is used to determine if the SVG can be paused and unpaused.
66→ * @param svgElement - The SVG element to check for animations.
67→ * @returns - A boolean indicating if the SVG element has animations.
68→ */
69→const hasAnimations = (svgElement: SVGSVGElement): boolean =>
70→  svgElement.querySelector("animate, animateTransform, animateMotion") !== null;
71→
72→export default AnimatedIcon;
