17→interface LoginPageProps {
18→  /**
19→   * If `ignoreAuthCheck` is true, the component will render without checking the user's authentication status.
20→   * This is useful for test environments where the user's authentication status is not relevant.
21→   */
22→  ignoreAuthCheck?: boolean;
23→}
24→const LoginPage: React.FC<LoginPageProps> = ({ ignoreAuthCheck }) => {
25→  const location = useLocation();
26→  const { hasCheckedAuth, isAuthenticated, localLogin } =
27→    useAuthProviderContext();
28→
29→  const [username, setUsername] = useState("");
30→  const [password, setPassword] = useState("");
31→
32→  if (!hasCheckedAuth && !ignoreAuthCheck) {
33→    return <FullPageLoad />;
34→  }
35→  return isAuthenticated ? (
36→    <Navigate to={getReferrer(location)} />
37→  ) : (
38→    <PageWrapper>
39→      <LoginForm
40→        onSubmit={(e) => {
41→          e.preventDefault();
42→          localLogin({ password, username });
