import { fn } from 'storybook/test';
import preview from '#.storybook/preview';
import { expect } from 'storybook/test';
import Pagination from './index';

const meta = preview.meta({
  component: Pagination,
  tags: ['ai-generated'],
  parameters: {
    layout: 'centered',
  },
});

export default meta;

export const FirstPage = meta.story({
  args: {
    currentPage: 0,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('1 / 5')).toBeVisible();
    // Prev button should be disabled on first page
    const buttons = canvas.getAllByRole('button');
    const prevButton = buttons[0];
    await expect(prevButton).toHaveAttribute('aria-disabled', 'true');
  },
});

export const MiddlePage = meta.story({
  args: {
    currentPage: 2,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('3 / 5')).toBeVisible();
  },
});

export const LastPage = meta.story({
  args: {
    currentPage: 4,
    totalResults: 50,
    pageSize: 10,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('5 / 5')).toBeVisible();
    // Next button should be disabled on last page
    const buttons = canvas.getAllByRole('button');
    const nextButton = buttons[buttons.length - 1];
    await expect(nextButton).toHaveAttribute('aria-disabled', 'true');
  },
});

export const WithCountLimit = meta.story({
  args: {
    currentPage: 0,
    totalResults: 1000,
    pageSize: 10,
    countLimit: 1000,
    onChange: fn(),
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('1 / many')).toBeVisible();
  },
});

import { useRef, useState } from 'react';
import { Button } from '@leafygreen-ui/button';
import preview from '#.storybook/preview';
import { expect, waitFor } from 'storybook/test';
import Popconfirm from './index';

const meta = preview.meta({
  component: Popconfirm,
  tags: ['ai-generated'],
  parameters: {
    layout: 'centered',
  },
});

export default meta;

export const Default = meta.story({
  render: () => {
    const [open, setOpen] = useState(false);
    const triggerRef = useRef<HTMLButtonElement>(null);
    return (
      <>
        <Button ref={triggerRef} onClick={() => setOpen((o) => !o)}>
          Delete Item
        </Button>
        <Popconfirm
          onConfirm={() => setOpen(false)}
          open={open}
          setOpen={setOpen}
          refEl={triggerRef}
        >
          Are you sure you want to delete this?
        </Popconfirm>
      </>
    );
  },
  play: async ({ canvas }) => {
    const trigger = canvas.getByRole('button', { name: /delete item/i });
    await expect(trigger).toBeVisible();
  },
});

export const WithCustomConfirmText = meta.story({
  render: () => {
    const [open, setOpen] = useState(false);
    const triggerRef = useRef<HTMLButtonElement>(null);
    return (
      <>
        <Button ref={triggerRef} onClick={() => setOpen((o) => !o)}>
          Remove Task
        </Button>
        <Popconfirm
          confirmText="Delete"
          onConfirm={() => setOpen(false)}
          open={open}
          setOpen={setOpen}
          refEl={triggerRef}
        >
          This action cannot be undone.
        </Popconfirm>
      </>
    );
  },
  play: async ({ canvas }) => {
    const trigger = canvas.getByRole('button', { name: /remove task/i });
    await expect(trigger).toBeVisible();
  },
});

export const ConfirmDisabled = meta.story({
  render: () => {
    const [open, setOpen] = useState(false);
    const triggerRef = useRef<HTMLButtonElement>(null);
    return (
      <>
        <Button ref={triggerRef} onClick={() => setOpen((o) => !o)}>
          Archive
        </Button>
        <Popconfirm
          confirmDisabled
          onConfirm={() => {}}
          open={open}
          setOpen={setOpen}
          refEl={triggerRef}
        >
          Confirm is disabled until conditions are met.
        </Popconfirm>
      </>
    );
  },
  play: async ({ canvas }) => {
    const trigger = canvas.getByRole('button', { name: /archive/i });
    await expect(trigger).toBeVisible();
  },
});

